import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F13_資本支出效能與股利防禦_投資研究員.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F13_資本支出效能與股利防禦_投資研究員.md"}'),i={name:"審計報告庫/財務審計/6903_巨漢/20260502/F13_資本支出效能與股利防禦_投資研究員.md"};function n(l,a,_,s,p,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>資本支出效能與股利防禦</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢 CapEx 節制（年約 3.3 億，營收比 10%），FCF 2025 年轉正至 4.53 億。現金股利從 2023 年 18 元降至 2025 年 8 元，主因股數膨脹稀釋，非現金問題。帳上現金 17-22 億，股利防禦力極強，無借債配息壓力。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A-（良）。FCF 已轉正且持續改善，股利覆蓋率 &gt;2 倍。利空：現金股利逐年下降（18→9.3→8 元）雖非現金問題，但對追求穩定現金流的投資人而言吸引力降低。此外，帳上現金過多卻無具體運用計畫，資本效率偏低將限制股東報酬。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>CapEx 效能</strong>：CapEx 年約 3.3 億，主要為辦公據點搬遷與設備更新，非產能擴張型支出。CapEx/營收比從 2024 年 18.6%（含一次性購置成本）降至 2025 年 10.3%。營收成長 72.8% 僅需 3.3 億 CapEx，顯示輕資產模式的高效率與靈活性，資產運用效率優於同業。</p></li><li><p><strong>FCF 分析</strong>：2024 年 FCF -1.89 億（因 CapEx 高峰 + CFO 轉負），2025 年大幅改善至 4.53 億。FCF 轉正速度優於預期，反映營運現金流強勁復甦。2026 年預估 FCF 有望維持 3-5 億水準，股利可維持性無虞。</p></li><li><p><strong>股利防禦</strong>：近 3 年現金股利分別為 18→9.3→8 元/股，雖逐年下降但總股利金額變化不大（主因股數膨脹）。2025 年總股利支出約 5.3 億，FCF 4.53 億覆蓋率約 85%，加上帳上現金 17-22 億，股利支付無資金壓力。股利政策保守穩健，無過度配發壓力。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>股利連續下滑的風險</strong>：每股現金股利 3 年內從 18 元降至 8 元（-56%），雖主因股數膨脹稀釋，但投資人看到的是「連年減少」的事實。若未來 EPS 無法成長，股利恐持續縮水，高股息投資人可能退出。</li><li><strong>過剩現金的資本效率問題</strong>：帳上現金 17-22 億（每股 25-33 元）遠超營運需求，但管理層未提出資金運用計畫。不增發股利也不擴張業務，現金效率持續低落，未來可能面臨股東要求提高配息的壓力。</li><li><strong>零借款的稅盾損失</strong>：公司無任何借款，雖安全但也損失了利息費用的稅盾效益。以目前營運規模，適度借款（5-10 億）可提升 ROE 又不至於增加財務風險，管理層的零借款政策過於保守，不利股東權益最大化。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><p>財務分析工具.py：capex_efficiency 6903 FinMind：TaiwanStockDividend（2023-2025）</p>',12)])])}const F=e(i,[["render",n]]);export{c as __pageData,F as default};
